ALTER TABLE "CustomerRelationship" ADD FOREIGN KEY ("CustomerID2") REFERENCES "Customer" ("CustomerID") DEFERRABLE INITIALLY IMMEDIATE;

ALTER TABLE "CustomerContractRole" ADD FOREIGN KEY ("CustomerID") REFERENCES "Customer" ("CustomerID") DEFERRABLE INITIALLY IMMEDIATE;

ALTER TABLE "CustomerContractRole" ADD FOREIGN KEY ("ContractID") REFERENCES "Contract" ("ContractID") DEFERRABLE INITIALLY IMMEDIATE;

ALTER TABLE "CustomerContractBenefitRole" ADD FOREIGN KEY ("CustomerID") REFERENCES "Customer" ("CustomerID") DEFERRABLE INITIALLY IMMEDIATE;

ALTER TABLE "CustomerContractBenefitRole" ADD FOREIGN KEY ("ContractBenefitID") REFERENCES "ContractBenefit" ("ContractBenefitID") DEFERRABLE INITIALLY IMMEDIATE;

